import numpy as np

# Mocking a WFS object structure for demonstration
class MockSource:
    def __init__(self):
        self.phase = np.zeros((100, 100))

class MockTelescope:
    def __init__(self):
        self.src = MockSource()

class MockWFS:
    def __init__(self):
        self.telescope = MockTelescope()
        self.nSubap = 2  # 2x2 grid
        self.nValidSubaperture = 3
        # Mask for 4 subaps, say one is invalid
        self.valid_subapertures_1D = [True, True, True, False]

    def get_lenslet_em_field(self, phase):
        # Return dummy EM field cube: (n_subaps_total, pix, pix)
        # 4 subaps, 16x16 pixels each
        return np.ones((4, 16, 16), dtype=complex)

